const SESSION_ID = 'YOUR_SESSION_ID';
const contacts = [
  { phone: '1234567890', name: 'Alice Johnson', amount: '$150.00', due_date: '2026-02-20' },
  { phone: '0987654321', name: 'Bob Smith', amount: '$320.00', due_date: '2026-02-22' }
];
const messageTemplate = 'Hi {{name}}, this is a friendly reminder that your payment of {{amount}} is due on {{due_date}}. Please let us know if you have any questions. Thank you!';
const items = contacts.map(contact => {
  const message = messageTemplate.replace('{{name}}', contact.name).replace('{{amount}}', contact.amount).replace('{{due_date}}', contact.due_date);
  return { json: { session_id: SESSION_ID, chat_id: contact.phone + '@c.us', message, contact_name: contact.name, contact_phone: contact.phone } };
});
return items;

const items = $input.all();
const results = items.map(item => {
  const data = item.json.body || item.json;
  return { status: 'sent', contact: item.json.contact_name || 'unknown', message_id: data.id || 'N/A', wa_status: data.status || 'N/A' };
});
return [{ json: { summary: 'Successfully sent ' + results.length + ' payment reminder(s)', results } }];

const items = $input.all();
const failures = items.map(item => {
  const data = item.json.body || item.json;
  return { status: 'failed', contact: item.json.contact_name || 'unknown', error: data.detail || data.message || 'HTTP ' + item.json.statusCode, status_code: item.json.statusCode };
});
return [{ json: { summary: 'Failed to send ' + failures.length + ' reminder(s)', failures } }];
